defmodule SecureSessionPlug do
  @moduledoc """
  Plug for handling secure session management in Phoenix applications.
  """
  import Plug.Conn

  @session_cookie "_secure_session"

  def init(opts), do: opts

  def call(conn, _opts) do
    secret_key_base = get_secret_key_base(conn)
    
    case get_session_cookie(conn) do
      nil ->
        conn
      
      token ->
        case SecureSessionManager.deserialize_session(token, secret_key_base) do
          {:ok, session} ->
            assign(conn, :current_session, session)
          
          {:error, _reason} ->
            conn
            |> delete_resp_cookie(@session_cookie)
        end
    end
  end

  def put_session(conn, session) do
    secret_key_base = get_secret_key_base(conn)
    token = SecureSessionManager.serialize_session(session, secret_key_base)
    
    put_resp_cookie(conn, @session_cookie, token,
      http_only: true,
      secure: true,
      same_site: "Lax",
      max_age: 86400
    )
  end

  def delete_session(conn) do
    delete_resp_cookie(conn, @session_cookie)
  end

  def get_current_session(conn) do
    conn.assigns[:current_session]
  end

  defp get_session_cookie(conn) do
    conn.cookies[@session_cookie]
  end

  defp get_secret_key_base(conn) do
    conn.secret_key_base || Application.get_env(:my_app, MyAppWeb.Endpoint)[:secret_key_base]
  end
end